function u(t){return t==="mi"||t==="m"?t:"km"}function a(t){return t==="m"?10:t==="mi"?.05:.1}function o(t){return t==="m"?1:.01}function r(t,n){const e=Math.max(0,t);return n==="m"?Math.round(e):Math.round(e*1e3)/1e3}function c(t,n){const e=r(t,n);return n==="m"?`${e} m`:`${Math.abs(e-Math.round(e))<1e-9?String(Math.round(e)):e.toFixed(2).replace(/\.?0+$/,"")} ${n}`}function f(t){return t==="time"?"time":t==="distance"?"distance":"reps"}function i(t){return t==="kg"?"kg":"lb"}function m(t){return i(t.weightUnit??t.exercise.weightUnit)}function d(t){return t==="kg"?1:2.5}function h(t){const n=Math.round(Math.max(0,t)*2)/2;return Number.isInteger(n)?String(n):n.toFixed(1)}export{u as a,h as b,m as c,d,c as f,o as m,f as p,r,a as s};
